    faqs: [
      { question: "Which Markdown flavor is used?", answer: "CommonMark/GFM-like features are typical; advanced extensions may differ from GitHub’s renderer." },
      { question: "Are raw HTML blocks in Markdown preserved?", answer: "Many converters allow inline HTML—treat untrusted input carefully." },
      { question: "Do tables work?", answer: "Pipe tables often work when GFM-style support is enabled; verify in preview." },
      { question: "Will classes and IDs be generated for headings?", answer: "Depends on the converter options—do not assume automatic heading IDs." },
      { question: "Is this enough for a static site?", answer: "It helps preview; production sites usually run Markdown through their SSG pipeline." },
    ],
